SELECT /*+ INDEX_DESC(A PPS_DEPOSIT_DATE_IDX) */ AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NAME, DEPOSIT_TYPE, NVL((SELECT CD_NM FROM PPS_KT_COMMON_CD WHERE TABLE_NM='PPS_AGENT_DEPOSIT' AND COL='DEPOSIT_TYPE' AND CD= A.DEPOSIT_TYPE),'') DEPOSIT_TYPE_NAME, CONTRACT_NUM, TO_CHAR(DEPOSIT_DATE, 'YYYY-MM-DD HH24:MI:SS') DEPOSIT_DATE, RECHARGE, MINUS_DEPOSIT, PLUS_DEPOSIT, REMAINS, ADMIN_ID, NVL(F_GET_ADMIN_NM(ADMIN_ID),'-') ADMIN_NM, REMARK FROM PPS_AGENT_DEPOSIT A WHERE DEPOSIT_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND DEPOSIT_DATE > ADD_MONTHS(SYSDATE,-12)
AND AGENT_ID = #{searchNm}
AND CONTRACT_NUM = #{searchNm}
AND AGENT_ID = #{searchAgentId}
AND DEPOSIT_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND DEPOSIT_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND DEPOSIT_TYPE= #{searchOrgDepositGubun}

SELECT /*+ INDEX_DESC(A PPS_DEPOSIT_DATE_IDX) */ NVL(AGENT_ID, '') ADMINID, NVL(FN_GET_ORGNM(AGENT_ID), '') AGENTNAME, NVL(DEPOSIT_TYPE, '') DEPOSITTYPE, NVL((SELECT CD_NM FROM PPS_KT_COMMON_CD WHERE TABLE_NM='PPS_AGENT_DEPOSIT' AND COL='DEPOSIT_TYPE' AND CD= A.DEPOSIT_TYPE),'-') DEPOSITTYPENAME, NVL(CONTRACT_NUM, '-') CONTRACTNUM, NVL(TO_CHAR(DEPOSIT_DATE, 'YYYY-MM-DD HH24:MI:SS'),'') DEPOSITDATE, NVL(RECHARGE, '0') RECHARGE, NVL(MINUS_DEPOSIT, '0') MINUSDEPOSIT, NVL(PLUS_DEPOSIT,'') PLUSDEPOSIT, NVL(REMAINS, '0') REMAINS, NVL(ADMIN_ID,'') ADMINID, NVL(F_GET_ADMIN_NM(ADMIN_ID),'') ADMINNM, NVL(REMARK,'') REMARK FROM PPS_AGENT_DEPOSIT A WHERE DEPOSIT_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND DEPOSIT_DATE > ADD_MONTHS(SYSDATE,-12)
AND AGENT_ID = #{searchNm}
AND CONTRACT_NUM = #{searchNm}
AND AGENT_ID = #{searchAgentId}
AND DEPOSIT_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND DEPOSIT_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
DEPOSIT_TYPE= #{searchOrgDepositGubun}

SELECT ORDER_SEQ, ORDER_ITEM, F_GET_KT_CODE_NM('PPS_ONLINE_ORDER', 'ORDER_ITEM', ORDER_ITEM) ORDER_ITEM_NM, MODEL_NM, AMOUNT, TO_CHAR(SHIP_DATE, 'YYYY-MM-DD') SHIP_DATE, SHIP_ADDRESS, OP_NM, OP_PHONE, AGENT_MEMO, AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NAME, TO_CHAR(REQ_DATE, 'YYYY-MM-DD') REQ_DATE, TO_CHAR(RECORD_DATE, 'YYYY-MM-DD') RECORD_DATE, STATUS, DECODE(STATUS,'0','접수','1','처리중','처리완료') STATUS_NM, TO_CHAR(OP_DATE, 'YYYY-MM-DD') OP_DATE, ADMIN_ID, BONSA_ADMIN_ID, ADMIN_MEMO, TO_CHAR(FINISH_DATE, 'YYYY-MM-DD HH:MI:SS') AS FINISH_DATE FROM PPS_ONLINE_ORDER A WHERE RECORD_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND AGENT_ID LIKE #{searchNm}
AND AGENT_ID = #{searchAgentId}
AND STATUS = #{searchStatus}

SELECT ORDER_SEQ ORDERSEQ, ORDER_ITEM ORDERITEM, F_GET_KT_CODE_NM('PPS_ONLINE_ORDER', 'ORDER_ITEM', ORDER_ITEM) ORDERITEMNM, MODEL_NM MODELNM, AMOUNT, TO_CHAR(SHIP_DATE, 'YYYY-MM-DD') SHIPDATE, SHIPADDRESS, OP_NM OPNM, OP_PHONE OPPHONE, AGENT_MEMO AGENTMEMO, AGENT_ID AGENTID, FN_GET_ORGNM(AGENT_ID) AGENTNAME, TO_CHAR(REQ_DATE, 'YYYY-MM-DD') REQDATE, TO_CHAR(RECORD_DATE, 'YYYY-MM-DD') RECORDDATE, STATUS, DECODE(STATUS,'0','접수','1','처리중','처리완료') STATUSNM, NVL(TO_CHAR(OP_DATE, 'YYYY-MM-DD'),'-') OPDATE, NVL(ADMIN_ID,'-') ADMINID, NVL(BONSA_ADMIN_ID,'-') BONSAADMINID , NVL(ADMIN_MEMO,'-') ADMINMEMO, NVL(TO_CHAR(FINISH_DATE, 'YYYY-MM-DD HH:MI:SS'),'-') AS FINISHDATE FROM PPS_ONLINE_ORDER A WHERE RECORD_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND AGENT_ID LIKE #{searchNm}
AND AGENT_ID = #{searchAgentId}
AND STATUS = #{searchStatus}

    	{CALL P_ONLINE_ORDER_ADMIN(
						#{orderSeq, jdbcType=VARCHAR}
						, #{status, jdbcType=VARCHAR}
						, #{adminId, jdbcType=VARCHAR}
						, #{adminMemo, jdbcType=VARCHAR}
						, #{oRetCode, mode=OUT, javaType=string, jdbcType=VARCHAR}
						, #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
						)
		}

    	{CALL P_ONLINE_ORDER(
						#{opCode, jdbcType=VARCHAR} 
						, #{orderSeq, jdbcType=VARCHAR} 
						, #{orderItem, jdbcType=VARCHAR} 
						, #{modelNm, jdbcType=VARCHAR} 
