						, #{oRetCode, mode=OUT, javaType=string, jdbcType=VARCHAR}
						, #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
						)
		}

SELECT A.AGENT_ID AGENT_ID, B.ORGN_NM AGENT_NM, B.TELNUM TELNUM, B.FAX FAX, B.RPRSEN_NM RPRSEN_NM, B.RESPN_PRSN_NUM RESPN_PRSN_NUM, TO_CHAR( A.DEPOSIT , '999,999,999,999,999') DEPOSIT, A.DEPOSIT_RATE DEPOSIT_RATE, A.PPS35_DEPOSIT_RATE PPS35_DEPOSIT_RATE, A.DATA_RATE DATA_RATE, A.PIN_BUY_RATE PIN_BUY_RATE, A.RENTAL_FEE RENTAL_FEE, A.VIR_ACCOUNT_ID VIR_ACCOUNT_ID, NVL(F_GET_VAC_BANK_NAME(A.VIR_ACCOUNT_ID),'') VIR_BANK_NM, NVL(F_GET_VAC_BANK_CODE(A.VIR_ACCOUNT_ID),'') VIR_BANK_CD, A.ADMIN_ID ADMIN_ID, F_GET_ADMIN_NM(A.ADMIN_ID) ADMIN_NM, TO_CHAR(B.REG_DTTM,'YYYY-MM-DD') REG_DTTM FROM PPS_AGENT A,ORG_ORGN_INFO_MST B WHERE A.AGENT_ID = B.ORGN_ID AND B.ORGN_LVL_CD ='10' AND B.TYPE_CD='20' AND B.TYPE_DTL_CD1='SU' AND B.TYPE_DTL_CD2 ='SU1'
AND A.AGENT_ID = #{searchAgentNm}
AND A.VIR_ACCOUNT_ID IS NOT NULL
AND A.VIR_ACCOUNT_ID IS NULL
AND A.DEPOSIT >= #{searchStartDeposit}
AND A.DEPOSIT <= #{searchEndDeposit}

SELECT NVL(A.AGENT_ID,'-') AGENTID, NVL(B.ORGN_NM,'-') AGENTNM, NVL(B.TELNUM,'-') TELNUM, NVL(B.FAX,'-') FAX, NVL(B.RPRSEN_NM,'-') RPRSENNM, NVL(B.RESPN_PRSN_NUM,'-') RESPNPRSNNUM, NVL(A.DEPOSIT,0) DEPOSIT, NVL(A.DEPOSIT_RATE,0) DEPOSITRATE, NVL(A.PPS35_DEPOSIT_RATE,0) PPS35DEPOSITRATE, NVL(A.DATA_RATE,0) DATARATE, NVL(A.PIN_BUY_RATE,0) PINBUYRATE, NVL(A.RENTAL_FEE,0) RENTALFEE, NVL(A.VIR_ACCOUNT_ID,'-') VIRACCOUNTID, NVL(F_GET_VAC_BANK_NAME(A.VIR_ACCOUNT_ID),'-') VIRBANKNM, NVL(A.ADMIN_ID,'-') ADMINID, NVL(F_GET_ADMIN_NM(A.ADMIN_ID),'-') ADMINNM, NVL(TO_CHAR(B.REG_DTTM,'YYYY-MM-DD'),'-') REGDTTM FROM PPS_AGENT A,ORG_ORGN_INFO_MST B WHERE A.AGENT_ID = B.ORGN_ID AND B.ORGN_LVL_CD ='10' AND B.TYPE_CD='20' AND B.TYPE_DTL_CD1='SU' AND B.TYPE_DTL_CD2 ='SU1'
AND A.AGENT_ID = #{searchAgentNm}
AND A.VIR_ACCOUNT_ID IS NOT NULL
AND A.VIR_ACCOUNT_ID IS NULL
AND A.DEPOSIT >= #{searchStartDeposit}
AND A.DEPOSIT <= #{searchEndDeposit}
